import './index.css';

import {
  useEffect,
  useState
} from 'react';

import Header
from '../../components/common/Header';

import {
  getSubjects
} from '../../services/subjectService';

function StudentSubjects() {

  const [subjects, setSubjects] =
    useState([]);

  const [loading, setLoading] =
    useState(true);

  useEffect(() => {

    loadSubjects();

  }, []);

  // LOAD SUBJECTS
  const loadSubjects =
    async () => {

    try {

      const data =
        await getSubjects();

      console.log(data);

      setSubjects(data);

    } catch (error) {

      console.log(error);

    } finally {

      setLoading(false);

    }

  };

  return (

    <div className="student-subjects">

      {/* HEADER */}

      <Header />


      {/* CONTENT */}

      <div className="student-subjects-content">

        <h1>
          My Subjects
        </h1>

        {

          loading
          ? (

            <h2>
              Loading...
            </h2>

          )
          : (

            <div className="subject-grid">

              {

                subjects.length > 0
                ? (

                  subjects.map((subject) => (

                    <div
                      key={subject.id}
                      className="subject-card"
                    >

                      <h3>
                        {subject.subject_name}
                      </h3>

                      <p>

                        <strong>
                          Subject ID:
                        </strong>

                        {' '}

                        {subject.id}

                      </p>

                      <p>

                        <strong>
                          Semester:
                        </strong>

                        {' '}

                        {subject.semester}

                      </p>

                    </div>

                  ))

                )
                : (

                  <div className="empty-box">

                    No Subjects Available

                  </div>

                )

              }

            </div>

          )

        }

      </div>

    </div>

  );

}

export default StudentSubjects;
